module RefModule (
    input [7:0] data_in,
    output reg [7:0] checksum_out
);
  wire [7:0] _tap_data_in = data_in & {8{1'b1}};

    integer i;
    reg [7:0] sum;

    always @(*) begin
        sum = 8'b0;
        for (i = 0; i < 8; i = i + 1) begin
            sum = sum + data_in[i];
        end
        checksum_out = sum % 256;
    end
endmodule
